const raw = $input.first().json;
const params = raw.parameters ?? {};
const ioc = params.ioc ?? params.value ?? params.indicator ?? null;
const iocType = params.ioc_type ?? params.type ?? 'ip-dst';
// Cortex dataType vocabulary differs from MISP attribute types
const CORTEX_TYPE_MAP = {
  'ip-dst': 'ip', 'ip-src': 'ip', 'domain': 'domain', 'hostname': 'domain',
  'url': 'url', 'md5': 'hash', 'sha1': 'hash', 'sha256': 'hash',
  'email-src': 'mail', 'email-dst': 'mail', 'filename': 'filename',
  'regkey': 'registry', 'mutex': 'other'
};
// OpenCTI stixCyberObservable type vocabulary
const OPENCTI_TYPE_MAP = {
  'ip-dst': 'IPv4-Addr', 'ip-src': 'IPv4-Addr', 'domain': 'Domain-Name',
  'hostname': 'Domain-Name', 'url': 'Url', 'md5': 'File', 'sha1': 'File',
  'sha256': 'File', 'email-src': 'Email-Addr', 'email-dst': 'Email-Addr',
  'filename': 'File'
};
if (!ioc) throw new Error('Sandbox: parameters.ioc is required');
const proposedActionId = raw.proposed_action_id ?? 'unknown';
const cortexType = CORTEX_TYPE_MAP[iocType] ?? 'other';
const openctiType = OPENCTI_TYPE_MAP[iocType] ?? 'Unknown';
return [{ json: { ioc, ioc_type: iocType, cortex_type: cortexType, opencti_type: openctiType, proposed_action_id: proposedActionId, action: raw.action, requester: raw.requester } }];

const misp = $input.item.json;
const input = $('Normalise Input').first().json;
const attributes = misp.response?.Attribute ?? [];
const eventIds = [...new Set(attributes.map(a => a.event_id))];
const tags = attributes.flatMap(a => (a.Tag ?? []).map(t => t.name));
const uniqueTags = [...new Set(tags)];
const tlp = uniqueTags.find(t => t.toLowerCase().startsWith('tlp:')) ?? 'tlp:white';
const mispFound = attributes.length > 0;
return [{ json: { ...input, misp_found: mispFound, misp_attributes: attributes, misp_event_ids: eventIds, misp_tags: uniqueTags, tlp } }];

const cortex = $input.item.json;
const input = $('Parse MISP Results').first().json;
const jobId = cortex.id ?? null;
if (!jobId) throw new Error('Cortex job submission failed: ' + JSON.stringify(cortex));
return [{ json: { ...input, cortex_job_id: jobId, cortex_status: cortex.status ?? 'Waiting', cortex_poll_count: 0 } }];

const item = $input.first().json;
const pollCount = item.cortex_poll_count ?? 0;
if (pollCount >= 10) throw new Error(`Cortex job ${item.cortex_job_id} did not complete after 10 polls (30s). Last status: ${item.cortex_status}`);
// n8n wait: sleep 3 seconds
await new Promise(r => setTimeout(r, 3000));
return [{ json: { ...item, cortex_poll_count: pollCount + 1 } }];

const report = $input.item.json;
const prev = $('Wait 3s').first().json;
const newStatus = report.status ?? prev.cortex_status;
return [{ json: { ...prev, cortex_status: newStatus, cortex_report: report, cortex_poll_count: prev.cortex_poll_count } }];

const opencti = $input.item.json;
const input = $('Update Status').first()?.json ?? $('Parse Cortex Submit').first().json;
if (opencti.errors?.length) {
  return [{ json: {
    status: 'partial',
    result_summary: `IOC ${input.ioc} processed. MISP hits: ${input.misp_attributes?.length ?? 0}. Cortex job: ${input.cortex_job_id}. OpenCTI push failed: ${opencti.errors[0].message}`,
    raw_result_ref: null,
    ioc: input.ioc, ioc_type: input.ioc_type,
    misp_found: input.misp_found, misp_event_ids: input.misp_event_ids,
    cortex_job_id: input.cortex_job_id, cortex_status: input.cortex_status,
    opencti_id: null, proposed_action_id: input.proposed_action_id
  } }];
}
const openctiId = opencti.data?.stixCyberObservableAdd?.id ?? null;
const success = !!openctiId;
return [{ json: {
  status: success ? 'success' : 'partial',
  result_summary: success
    ? `IOC ${input.ioc} (${input.ioc_type}) enriched. MISP hits: ${input.misp_attributes?.length ?? 0}. Cortex job: ${input.cortex_job_id} (${input.cortex_status}). OpenCTI ID: ${openctiId}.`
    : `IOC ${input.ioc} processed. MISP hits: ${input.misp_attributes?.length ?? 0}. OpenCTI push returned no ID.`,
  raw_result_ref: openctiId,
  ioc: input.ioc, ioc_type: input.ioc_type,
  misp_found: input.misp_found, misp_event_ids: input.misp_event_ids,
  cortex_job_id: input.cortex_job_id, cortex_status: input.cortex_status,
  opencti_id: openctiId, proposed_action_id: input.proposed_action_id
} }];
